import 'server-only';
import { SignJWT, jwtVerify } from 'jose';

// JWT issuer and audience configuration
const JWT_ISSUER = process.env.JWT_ISSUER || 'wmg2027-chatbot';
const JWT_AUDIENCE = process.env.JWT_AUDIENCE || 'wmg2027-admin';

/**
 * Get and validate JWT secret from environment
 * @throws Error if SESSION_SECRET is not set or too short
 */
function getJwtSecret(): Uint8Array {
  const sessionSecret = process.env.SESSION_SECRET;

  // Validate SESSION_SECRET is set in production
  if (!sessionSecret && process.env.NODE_ENV === 'production') {
    throw new Error('SESSION_SECRET environment variable is required in production');
  }

  // Use fallback only in development/test
  const secret = sessionSecret || 'wmg2027-session-secret-key-32chars';

  // Validate minimum length (32 chars for HS256)
  if (secret.length < 32) {
    throw new Error('SESSION_SECRET must be at least 32 characters');
  }

  return new TextEncoder().encode(secret);
}

/**
 * JWT トークンを生成
 * @returns JWT トークン文字列
 */
export async function createToken(): Promise<string> {
  const secret = getJwtSecret();

  // JWT_EXPIRES_IN: 秒数（例: "3600"）または時間文字列（例: "1h"）をサポート
  const expiresIn = process.env.JWT_EXPIRES_IN || '1h';

  // 数値のみの場合は秒数として扱い、相対時間形式に変換
  const expirationTime = /^\d+$/.test(expiresIn) ? `${expiresIn} seconds` : expiresIn;

  return new SignJWT({ authenticated: true })
    .setProtectedHeader({ alg: 'HS256' })
    .setIssuer(JWT_ISSUER)
    .setAudience(JWT_AUDIENCE)
    .setExpirationTime(expirationTime)
    .setIssuedAt()
    .sign(secret);
}

/**
 * JWT トークンを検証
 * @param token - JWT トークン文字列
 * @returns ペイロード（検証成功時）または null（検証失敗時）
 */
export async function verifyToken(token: string) {
  try {
    const secret = getJwtSecret();
    const { payload } = await jwtVerify(token, secret, {
      issuer: JWT_ISSUER,
      audience: JWT_AUDIENCE,
    });
    return payload;
  } catch {
    return null;
  }
}


