import 'server-only';
import crypto from 'crypto';

/**
 * Timing-safe password comparison
 * Uses crypto.timingSafeEqual to prevent timing attacks
 * @param input - User provided password
 * @param expected - Expected password from environment
 * @returns true if passwords match
 */
function timingSafeCompare(input: string, expected: string): boolean {
  // Convert strings to buffers for comparison
  const inputBuffer = Buffer.from(input, 'utf8');
  const expectedBuffer = Buffer.from(expected, 'utf8');

  // If lengths differ, we still need to do a constant-time comparison
  // to avoid leaking length information
  if (inputBuffer.length !== expectedBuffer.length) {
    // Compare against a buffer of the same length as input to maintain timing
    const paddedExpected = Buffer.alloc(inputBuffer.length, 0);
    expectedBuffer.copy(paddedExpected, 0, 0, Math.min(expectedBuffer.length, inputBuffer.length));
    crypto.timingSafeEqual(inputBuffer, paddedExpected);
    return false;
  }

  return crypto.timingSafeEqual(inputBuffer, expectedBuffer);
}

/**
 * パスワードを検証
 * 環境変数 ADMIN_PASSWORD と比較して認証を行う
 * タイミング攻撃を防ぐためcrypto.timingSafeEqualを使用
 * @param password - 検証するパスワード
 * @returns 検証結果（true: 成功, false: 失敗）
 */
export function verifyPassword(password: string): boolean {
  const adminPassword = process.env.ADMIN_PASSWORD;

  if (!adminPassword) {
    console.error('ADMIN_PASSWORD is not set in environment variables');
    return false;
  }

  return timingSafeCompare(password, adminPassword);
}


