/**
 * API Error Handler Middleware
 * Provides consistent error handling for API routes
 */

import { NextResponse } from 'next/server';
import { logger, generateRequestId, createRequestLogger } from '@/server/lib/logger';
import { CircuitBreakerOpenError } from './rate-limiter';

/**
 * Standard API error response structure
 */
export interface ApiErrorResponse {
  error: {
    message: string;
    code: string;
    details?: unknown;
  };
}

/**
 * Custom API error class with status code and error code
 */
export class ApiError extends Error {
  constructor(
    public readonly statusCode: number,
    public readonly code: string,
    message: string,
    public readonly details?: unknown
  ) {
    super(message);
    this.name = 'ApiError';
  }

  /**
   * Factory method for 400 Bad Request
   */
  static badRequest(message: string, details?: unknown): ApiError {
    return new ApiError(400, 'BAD_REQUEST', message, details);
  }

  /**
   * Factory method for 401 Unauthorized
   */
  static unauthorized(message = 'Unauthorized'): ApiError {
    return new ApiError(401, 'UNAUTHORIZED', message);
  }

  /**
   * Factory method for 403 Forbidden
   */
  static forbidden(message = 'Forbidden'): ApiError {
    return new ApiError(403, 'FORBIDDEN', message);
  }

  /**
   * Factory method for 404 Not Found
   */
  static notFound(message = 'Resource not found'): ApiError {
    return new ApiError(404, 'NOT_FOUND', message);
  }

  /**
   * Factory method for 429 Too Many Requests
   */
  static tooManyRequests(message = 'Too many requests'): ApiError {
    return new ApiError(429, 'TOO_MANY_REQUESTS', message);
  }

  /**
   * Factory method for 500 Internal Server Error
   */
  static internal(message = 'Internal server error', details?: unknown): ApiError {
    return new ApiError(500, 'INTERNAL_ERROR', message, details);
  }

  /**
   * Factory method for 503 Service Unavailable
   */
  static serviceUnavailable(message = 'Service temporarily unavailable'): ApiError {
    return new ApiError(503, 'SERVICE_UNAVAILABLE', message);
  }
}

/**
 * Convert error to standardized API response
 */
export function toErrorResponse(error: unknown): {
  response: ApiErrorResponse;
  status: number;
  headers?: Record<string, string>;
} {
  if (error instanceof ApiError) {
    return {
      response: {
        error: {
          message: error.message,
          code: error.code,
          details: error.details,
        },
      },
      status: error.statusCode,
    };
  }

  // Handle circuit breaker open errors
  if (error instanceof CircuitBreakerOpenError) {
    logger.warn({ retryAfter: error.retryAfter }, 'Circuit breaker is open');
    return {
      response: {
        error: {
          message: 'Service temporarily unavailable. Please try again later.',
          code: 'SERVICE_UNAVAILABLE',
          details: { retryAfter: error.retryAfter },
        },
      },
      status: 503,
      headers: {
        'Retry-After': String(error.retryAfter),
      },
    };
  }

  // Handle standard Error objects
  if (error instanceof Error) {
    logger.error({ error: error.message, stack: error.stack }, 'Unhandled error');
    return {
      response: {
        error: {
          message: 'An unexpected error occurred',
          code: 'INTERNAL_ERROR',
        },
      },
      status: 500,
    };
  }

  // Handle unknown error types
  logger.error({ error }, 'Unknown error type');
  return {
    response: {
      error: {
        message: 'An unexpected error occurred',
        code: 'INTERNAL_ERROR',
      },
    },
    status: 500,
  };
}

/**
 * Wrap API route handler with error handling
 * Usage:
 * ```ts
 * export const GET = withErrorHandler(async (request) => {
 *   // Your logic here
 *   return NextResponse.json({ data: 'success' });
 * });
 * ```
 */
export function withErrorHandler<T extends (...args: never[]) => Promise<Response>>(handler: T): T {
  return (async (...args: Parameters<T>): Promise<Response> => {
    const requestId = generateRequestId();
    const log = createRequestLogger(requestId);

    try {
      return await handler(...args);
    } catch (error) {
      const { response, status, headers } = toErrorResponse(error);
      log.error({ error, status }, 'Request failed');
      return NextResponse.json(response, {
        status,
        headers: {
          ...headers,
          'X-Request-Id': requestId,
        },
      });
    }
  }) as T;
}

/**
 * Helper function to create error response directly
 */
export function errorResponse(
  statusCode: number,
  code: string,
  message: string,
  details?: unknown
): NextResponse<ApiErrorResponse> {
  return NextResponse.json(
    {
      error: {
        message,
        code,
        details,
      },
    },
    { status: statusCode }
  );
}

